package main

import "fmt"

type book struct {
	title string
	pages int
}

func display(b book) {
	fmt.Printf("\"%s\" — %d pages\n", b.title, b.pages)
}

func main() {
	b := book{title: "The Great Gatsby", pages: 180}
	display(b)
}

