package main

import (
	"encoding/json"
	"fmt"
)

type Book struct {
	Title string `json:"title"`
	Author string `json:"author"`
	Pages int    `json:"pages"`
}

func main() {
	b := Book{Title: "The Great Gatsby", Author: "F. Scott Fitzgerald", Pages: 180}
	data, err := json.Marshal(b)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println(string(data))
}

